DROP TABLE IF EXISTS `dashboard_widgets`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `dashboard_widgets` (
  `id` int NOT NULL AUTO_INCREMENT,
  `widget_key` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL,
  `name` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `description` text COLLATE utf8mb4_unicode_ci,
  `category` enum('overview','subscriptions','dcr','opportunities','knowledge_base','common') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'common',
  `icon` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `default_width` int NOT NULL DEFAULT '4',
  `default_height` int NOT NULL DEFAULT '3',
  `min_width` int NOT NULL DEFAULT '2',
  `min_height` int NOT NULL DEFAULT '2',
  `max_width` int DEFAULT NULL,
  `max_height` int DEFAULT NULL,
  `default_config` json DEFAULT NULL,
  `data_endpoint` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `refresh_interval_seconds` int DEFAULT '300',
  `is_active` tinyint(1) NOT NULL DEFAULT '1',
  `sort_order` int NOT NULL DEFAULT '0',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `widget_key` (`widget_key`),
  KEY `idx_category` (`category`),
  KEY `idx_active` (`is_active`)
) ENGINE=InnoDB AUTO_INCREMENT=29 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
