INSERT INTO `email_templates` VALUES (1,'before_30','30 Days Before Expiry','Your subscription expires in 30 days','<html><body><div style=\"max-width: 800px; margin: 0 auto; font-family: Arial, sans-serif;\"><div style=\"padding: 20px; background-color: #fff3cd; border-left: 4px solid #ffc107; margin-bottom: 20px;\"><h2 style=\"margin: 0 0 10px; color: #856404;\">⚠️ Subscription Expiring Soon</h2><p style=\"margin: 0; color: #856404;\">Your subscription will expire in <strong>{{days_left}}</strong> days. Please review the details below and renew to avoid service interruption.</p></div>{{{invoice_html}}}<div style=\"text-align: center; padding: 20px; background-color: #f9f9f9; margin-top: 20px;\"><a href=\"{{renewal_link}}\" style=\"display: inline-block; padding: 12px 24px; background-color: #4A90E2; color: white; text-decoration: none; border-radius: 5px; font-weight: bold;\">Renew Subscription</a></div><div style=\"text-align: center; padding: 20px; color: #666; font-size: 12px;\"><p>Thank you for your business!</p><p>Support Team</p></div></div></body></html>',1,'2025-12-15 12:39:21','2025-12-30 12:35:32'),(2,'before_7','7 Days Before Expiry','Your subscription expires in 7 days','<html><body><div style=\"max-width: 800px; margin: 0 auto; font-family: Arial, sans-serif;\"><div style=\"padding: 20px; background-color: #f8d7da; border-left: 4px solid #dc3545; margin-bottom: 20px;\"><h2 style=\"margin: 0 0 10px; color: #721c24;\">🚨 URGENT: Subscription Expiring in {{days_left}} Days</h2><p style=\"margin: 0; color: #721c24; font-weight: bold;\">Immediate action required to avoid service disruption.</p></div>{{{invoice_html}}}<div style=\"text-align: center; padding: 20px; background-color: #f9f9f9; margin-top: 20px;\"><a href=\"{{renewal_link}}\" style=\"display: inline-block; padding: 12px 24px; background-color: #dc3545; color: white; text-decoration: none; border-radius: 5px; font-weight: bold;\">Renew Now</a></div><div style=\"text-align: center; padding: 20px; color: #666; font-size: 12px;\"><p>Thank you for your business!</p><p>Support Team</p></div></div></body></html>',1,'2025-12-15 12:39:21','2025-12-30 12:35:32'),(3,'on_expiry','On Expiry Date','Your subscription has expired','<html><body><div style=\"max-width: 800px; margin: 0 auto; font-family: Arial, sans-serif;\"><div style=\"padding: 20px; background-color: #f8d7da; border-left: 4px solid #dc3545; margin-bottom: 20px;\"><h2 style=\"margin: 0 0 10px; color: #721c24;\">❌ Subscription Has Expired</h2><p style=\"margin: 0; color: #721c24;\">Your subscription expired on <strong>{{end_date}}</strong>. Service has been discontinued. Please renew immediately to restore access.</p></div>{{{invoice_html}}}<div style=\"text-align: center; padding: 20px; background-color: #f9f9f9; margin-top: 20px;\"><a href=\"{{renewal_link}}\" style=\"display: inline-block; padding: 12px 24px; background-color: #dc3545; color: white; text-decoration: none; border-radius: 5px; font-weight: bold;\">Restore Service - Renew Now</a></div><div style=\"text-align: center; padding: 20px; color: #666; font-size: 12px;\"><p>Thank you for your business!</p><p>Support Team</p></div></div></body></html>',1,'2025-12-15 12:39:21','2025-12-30 12:35:32'),(4,'after_7','7 Days After Expiry','Your subscription expired 7 days ago','<html><body><div style=\"max-width: 800px; margin: 0 auto; font-family: Arial, sans-serif;\"><div style=\"padding: 20px; background-color: #f8d7da; border-left: 4px solid #dc3545; margin-bottom: 20px;\"><h2 style=\"margin: 0 0 10px; color: #721c24;\">⛔ Action Required: Subscription Expired {{days_left}} Days Ago</h2><p style=\"margin: 0; color: #721c24;\">Your subscription has been expired for 7 days. Please renew immediately to restore service and prevent data loss.</p></div>{{{invoice_html}}}<div style=\"text-align: center; padding: 20px; background-color: #f9f9f9; margin-top: 20px;\"><a href=\"{{renewal_link}}\" style=\"display: inline-block; padding: 12px 24px; background-color: #dc3545; color: white; text-decoration: none; border-radius: 5px; font-weight: bold;\">Renew Immediately</a></div><div style=\"text-align: center; padding: 20px; color: #666; font-size: 12px;\"><p>Thank you for your business!</p><p>Support Team</p></div></div></body></html>',1,'2025-12-15 12:39:21','2025-12-30 12:35:32'),(5,'renewal_invoice','Renewal Invoice','Your renewal invoice is ready','<html><body><div style=\"max-width: 800px; margin: 0 auto; font-family: Arial, sans-serif;\"><div style=\"padding: 20px; background-color: #d1ecf1; border-left: 4px solid #17a2b8; margin-bottom: 20px;\"><h2 style=\"margin: 0 0 10px; color: #0c5460;\">✅ Subscription Renewed Successfully</h2><p style=\"margin: 0; color: #0c5460;\">Your subscription has been renewed. Thank you for your continued business!</p></div>{{{invoice_html}}}<div style=\"text-align: center; padding: 20px; color: #666; font-size: 12px;\"><p>Thank you for your business!</p><p>Support Team</p></div></div></body></html>',1,'2025-12-15 12:39:21','2025-12-30 12:35:32'),(6,'birthday_wish','Birthday Wish','Happy Birthday {{name}}!','<html>\n<body style=\"font-family: Arial, sans-serif; line-height: 1.6; color: #333;\">\n    <div style=\"max-width: 600px; margin: 0 auto; padding: 20px;\">\n        <div style=\"background: linear-gradient(135deg, #667eea 0%, #764ba2 100%); padding: 30px; text-align: center; border-radius: 10px 10px 0 0;\">\n            <h1 style=\"color: #fff; margin: 0; font-size: 32px;\">🎉 Happy Birthday! 🎉</h1>\n        </div>\n        <div style=\"background: #f9f9f9; padding: 30px; border-radius: 0 0 10px 10px;\">\n            <p style=\"font-size: 18px; margin-bottom: 20px;\">Dear {{name}},</p>\n            <p style=\"font-size: 16px; margin-bottom: 20px;\">\n                On this special day, we want to take a moment to celebrate you! \n                {{#if isCustomer}}\n                Thank you for being a valued customer and for your continued trust in our services.\n                {{else}}\n                Thank you for being an integral part of our team and for all your hard work and dedication.\n                {{/if}}\n            </p>\n            <div style=\"background: #fff; padding: 20px; border-radius: 8px; margin: 20px 0; text-align: center;\">\n                <p style=\"font-size: 24px; font-weight: bold; color: #667eea; margin: 0;\">\n                    Wishing you a wonderful year ahead filled with joy, success, and happiness!\n                </p>\n            </div>\n            <p style=\"font-size: 16px; margin-top: 30px;\">\n                Best regards,<br>\n                <strong>The Subsync Team</strong>\n            </p>\n        </div>\n        <div style=\"text-align: center; margin-top: 20px; color: #999; font-size: 12px;\">\n            <p>This is an automated birthday wish from Subsync</p>\n        </div>\n    </div>\n</body>\n</html>',1,'2025-12-15 12:40:25','2025-12-15 12:40:25'),(7,'backup_success','Backup Success Notification','Backup Completed Successfully - {{config_name}}','<html>\n<body style=\"font-family: Arial, sans-serif; line-height: 1.6; color: #333;\">\n    <div style=\"max-width: 600px; margin: 0 auto; padding: 20px;\">\n        <div style=\"background: linear-gradient(135deg, #10b981 0%, #059669 100%); padding: 30px; text-align: center; border-radius: 10px 10px 0 0;\">\n            <h1 style=\"color: #fff; margin: 0; font-size: 28px;\">✅ Backup Completed Successfully</h1>\n        </div>\n        <div style=\"background: #f9f9f9; padding: 30px; border-radius: 0 0 10px 10px;\">\n            <h2 style=\"color: #059669; margin-top: 0;\">Backup Summary</h2>\n            \n            <table style=\"width: 100%; border-collapse: collapse; margin: 20px 0;\">\n                <tr>\n                    <td style=\"padding: 10px; border-bottom: 1px solid #ddd; font-weight: bold;\">Configuration:</td>\n                    <td style=\"padding: 10px; border-bottom: 1px solid #ddd;\">{{config_name}}</td>\n                </tr>\n                <tr>\n                    <td style=\"padding: 10px; border-bottom: 1px solid #ddd; font-weight: bold;\">Database:</td>\n                    <td style=\"padding: 10px; border-bottom: 1px solid #ddd;\">{{database_name}}</td>\n                </tr>\n                <tr>\n                    <td style=\"padding: 10px; border-bottom: 1px solid #ddd; font-weight: bold;\">Started:</td>\n                    <td style=\"padding: 10px; border-bottom: 1px solid #ddd;\">{{started_at}}</td>\n                </tr>\n                <tr>\n                    <td style=\"padding: 10px; border-bottom: 1px solid #ddd; font-weight: bold;\">Completed:</td>\n                    <td style=\"padding: 10px; border-bottom: 1px solid #ddd;\">{{completed_at}}</td>\n                </tr>\n                <tr>\n                    <td style=\"padding: 10px; border-bottom: 1px solid #ddd; font-weight: bold;\">Duration:</td>\n                    <td style=\"padding: 10px; border-bottom: 1px solid #ddd;\">{{duration_seconds}} seconds</td>\n                </tr>\n                <tr>\n                    <td style=\"padding: 10px; border-bottom: 1px solid #ddd; font-weight: bold;\">File Size:</td>\n                    <td style=\"padding: 10px; border-bottom: 1px solid #ddd;\">{{file_size_formatted}}</td>\n                </tr>\n                <tr>\n                    <td style=\"padding: 10px; font-weight: bold;\">Checksum:</td>\n                    <td style=\"padding: 10px; font-family: monospace; font-size: 12px;\">{{checksum}}</td>\n                </tr>\n            </table>\n            \n            <p style=\"margin-top: 30px; color: #666;\">\n                Your backup has been completed successfully and is securely stored. \n                This backup can be restored at any time from the Backup Management interface.\n            </p>\n            \n            <p style=\"margin-top: 20px;\">\n                Best regards,<br>\n                <strong>Subsync Backup System</strong>\n            </p>\n        </div>\n    </div>\n</body>\n</html>',1,'2025-12-17 05:14:54','2025-12-17 05:14:54'),(8,'backup_failure','Backup Failure Alert','⚠️ Backup Failed - {{config_name}}','<html>\n<body style=\"font-family: Arial, sans-serif; line-height: 1.6; color: #333;\">\n    <div style=\"max-width: 600px; margin: 0 auto; padding: 20px;\">\n        <div style=\"background: linear-gradient(135deg, #ef4444 0%, #dc2626 100%); padding: 30px; text-align: center; border-radius: 10px 10px 0 0;\">\n            <h1 style=\"color: #fff; margin: 0; font-size: 28px;\">⚠️ Backup Failed</h1>\n        </div>\n        <div style=\"background: #f9f9f9; padding: 30px; border-radius: 0 0 10px 10px;\">\n            <h2 style=\"color: #dc2626; margin-top: 0;\">Backup Failure Alert</h2>\n            \n            <div style=\"background: #fee2e2; border-left: 4px solid #dc2626; padding: 15px; margin: 20px 0;\">\n                <p style=\"margin: 0; font-weight: bold;\">Action Required</p>\n                <p style=\"margin: 5px 0 0 0;\">A backup operation has failed and requires immediate attention.</p>\n            </div>\n            \n            <table style=\"width: 100%; border-collapse: collapse; margin: 20px 0;\">\n                <tr>\n                    <td style=\"padding: 10px; border-bottom: 1px solid #ddd; font-weight: bold;\">Configuration:</td>\n                    <td style=\"padding: 10px; border-bottom: 1px solid #ddd;\">{{config_name}}</td>\n                </tr>\n                <tr>\n                    <td style=\"padding: 10px; border-bottom: 1px solid #ddd; font-weight: bold;\">Database:</td>\n                    <td style=\"padding: 10px; border-bottom: 1px solid #ddd;\">{{database_name}}</td>\n                </tr>\n                <tr>\n                    <td style=\"padding: 10px; border-bottom: 1px solid #ddd; font-weight: bold;\">Failed At:</td>\n                    <td style=\"padding: 10px; border-bottom: 1px solid #ddd;\">{{completed_at}}</td>\n                </tr>\n                <tr>\n                    <td style=\"padding: 10px; border-bottom: 1px solid #ddd; font-weight: bold;\">Retry Count:</td>\n                    <td style=\"padding: 10px; border-bottom: 1px solid #ddd;\">{{retry_count}}</td>\n                </tr>\n            </table>\n            \n            <div style=\"background: #fff; border: 1px solid #ddd; padding: 15px; margin: 20px 0; border-radius: 5px;\">\n                <h3 style=\"margin-top: 0; color: #dc2626;\">Error Details:</h3>\n                <p style=\"font-family: monospace; font-size: 13px; color: #666; margin: 0;\">{{error_message}}</p>\n            </div>\n            \n            <p style=\"margin-top: 30px; color: #666;\">\n                Please investigate this issue as soon as possible to ensure your data is properly backed up.\n            </p>\n            \n            <p style=\"margin-top: 20px;\">\n                Best regards,<br>\n                <strong>Subsync Backup System</strong>\n            </p>\n        </div>\n    </div>\n</body>\n</html>',1,'2025-12-17 05:14:54','2025-12-17 05:14:54'),(9,'backup_restore','Backup Restore Notification','Database Restored from Backup - {{config_name}}','<html>\n<body style=\"font-family: Arial, sans-serif; line-height: 1.6; color: #333;\">\n    <div style=\"max-width: 600px; margin: 0 auto; padding: 20px;\">\n        <div style=\"background: linear-gradient(135deg, #3b82f6 0%, #2563eb 100%); padding: 30px; text-align: center; border-radius: 10px 10px 0 0;\">\n            <h1 style=\"color: #fff; margin: 0; font-size: 28px;\">🔄 Database Restored</h1>\n        </div>\n        <div style=\"background: #f9f9f9; padding: 30px; border-radius: 0 0 10px 10px;\">\n            <h2 style=\"color: #2563eb; margin-top: 0;\">Restore Operation Completed</h2>\n            \n            <div style=\"background: #dbeafe; border-left: 4px solid #2563eb; padding: 15px; margin: 20px 0;\">\n                <p style=\"margin: 0; font-weight: bold;\">Important Notice</p>\n                <p style=\"margin: 5px 0 0 0;\">A database restore operation has been performed.</p>\n            </div>\n            \n            <table style=\"width: 100%; border-collapse: collapse; margin: 20px 0;\">\n                <tr>\n                    <td style=\"padding: 10px; border-bottom: 1px solid #ddd; font-weight: bold;\">Backup:</td>\n                    <td style=\"padding: 10px; border-bottom: 1px solid #ddd;\">{{config_name}}</td>\n                </tr>\n                <tr>\n                    <td style=\"padding: 10px; border-bottom: 1px solid #ddd; font-weight: bold;\">Database:</td>\n                    <td style=\"padding: 10px; border-bottom: 1px solid #ddd;\">{{database_name}}</td>\n                </tr>\n                <tr>\n                    <td style=\"padding: 10px; border-bottom: 1px solid #ddd; font-weight: bold;\">Restored At:</td>\n                    <td style=\"padding: 10px; border-bottom: 1px solid #ddd;\">{{restored_at}}</td>\n                </tr>\n                <tr>\n                    <td style=\"padding: 10px; border-bottom: 1px solid #ddd; font-weight: bold;\">Restored By:</td>\n                    <td style=\"padding: 10px; border-bottom: 1px solid #ddd;\">{{restored_by}}</td>\n                </tr>\n            </table>\n            \n            <p style=\"margin-top: 30px; color: #666;\">\n                The database has been successfully restored from the selected backup. \n                Please verify that all data is correct and functioning as expected.\n            </p>\n            \n            <p style=\"margin-top: 20px;\">\n                Best regards,<br>\n                <strong>Subsync Backup System</strong>\n            </p>\n        </div>\n    </div>\n</body>\n</html>',1,'2025-12-17 05:14:54','2025-12-17 05:14:54');
