--
-- Table structure for table `knowledge_article_access_log`
--

DROP TABLE IF EXISTS `knowledge_article_access_log`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `knowledge_article_access_log` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `article_id` int DEFAULT NULL,
  `article_slug` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `ip_address` varchar(45) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'IPv4 or IPv6 address',
  `ip_hash` varchar(64) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Hashed IP for privacy',
  `user_agent` text COLLATE utf8mb4_unicode_ci,
  `request_method` varchar(10) COLLATE utf8mb4_unicode_ci DEFAULT 'GET',
  `request_path` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `query_params` text COLLATE utf8mb4_unicode_ci,
  `response_status` int DEFAULT NULL,
  `response_time_ms` int DEFAULT NULL,
  `is_bot` tinyint(1) DEFAULT '0',
  `is_suspicious` tinyint(1) DEFAULT '0' COMMENT 'Flagged as suspicious activity',
  `suspicious_reason` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `accessed_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_article_id` (`article_id`),
  KEY `idx_ip_hash` (`ip_hash`),
  KEY `idx_accessed_at` (`accessed_at`),
  KEY `idx_suspicious` (`is_suspicious`,`accessed_at`),
  KEY `idx_ip_time` (`ip_address`,`accessed_at`)
) ENGINE=InnoDB AUTO_INCREMENT=9 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='Security audit log for public article access';
/*!40101 SET character_set_client = @saved_cs_client */;

