DROP TABLE IF EXISTS `knowledge_article_reads`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `knowledge_article_reads` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `article_id` int NOT NULL,
  `session_fingerprint` varchar(64) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Anonymous session identifier',
  `ip_hash` varchar(64) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Hashed IP address for privacy',
  `user_agent` text COLLATE utf8mb4_unicode_ci,
  `referrer` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `utm_source` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `utm_medium` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `utm_campaign` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `read_duration` int DEFAULT '0' COMMENT 'Time spent reading in seconds',
  `scroll_depth` int DEFAULT '0' COMMENT 'Percentage of article scrolled',
  `is_unique` tinyint(1) DEFAULT '1' COMMENT 'First read from this fingerprint',
  `read_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_article_id` (`article_id`),
  KEY `idx_fingerprint` (`session_fingerprint`),
  KEY `idx_read_at` (`read_at`),
  KEY `idx_unique_reads` (`article_id`,`is_unique`),
  CONSTRAINT `fk_reads_article` FOREIGN KEY (`article_id`) REFERENCES `knowledge_articles` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='Tracks individual article reads for analytics';
