--
-- Table structure for table `knowledge_articles`
--

DROP TABLE IF EXISTS `knowledge_articles`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `knowledge_articles` (
  `id` int NOT NULL AUTO_INCREMENT,
  `title` varchar(255) NOT NULL,
  `slug` varchar(255) NOT NULL,
  `content` longtext,
  `category_id` int DEFAULT NULL,
  `author_id` varchar(32) NOT NULL,
  `visibility` enum('internal','customer','both') NOT NULL DEFAULT 'internal',
  `is_published` tinyint(1) DEFAULT '0',
  `views` int DEFAULT '0',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `meta_title` varchar(60) DEFAULT NULL COMMENT 'SEO meta title (max 60 chars)',
  `meta_description` varchar(160) DEFAULT NULL COMMENT 'SEO meta description (max 160 chars)',
  `keywords` text COMMENT 'SEO keywords (comma-separated)',
  `canonical_url` varchar(255) DEFAULT NULL COMMENT 'Canonical URL for SEO',
  `og_image` varchar(500) DEFAULT NULL COMMENT 'Open Graph image URL',
  `total_reads` int DEFAULT '0' COMMENT 'Total read count',
  `unique_reads` int DEFAULT '0' COMMENT 'Unique visitor count',
  `last_read_at` timestamp NULL DEFAULT NULL COMMENT 'Last time article was read',
  PRIMARY KEY (`id`),
  UNIQUE KEY `slug_UNIQUE` (`slug`),
  KEY `idx_author_id` (`author_id`),
  KEY `idx_category_id` (`category_id`),
  KEY `idx_public_articles` (`visibility`,`is_published`,`slug`),
  KEY `idx_sitemap` (`visibility`,`is_published`,`updated_at`),
  FULLTEXT KEY `ft_search` (`title`,`content`),
  CONSTRAINT `knowledge_articles_ibfk_1` FOREIGN KEY (`category_id`) REFERENCES `knowledge_categories` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=10 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

